-- Canonical seed dataset shared by every oracle variant. We insert explicit
-- IDs; the IDENTITY's internal sequence auto-aligns under
-- `GENERATED BY DEFAULT ON NULL`.





-- Realign the identity sequences past the manually-set IDs.
ALTER TABLE "organization" MODIFY (id GENERATED BY DEFAULT ON NULL AS IDENTITY START WITH LIMIT VALUE);
ALTER TABLE app_user MODIFY (id GENERATED BY DEFAULT ON NULL AS IDENTITY START WITH LIMIT VALUE);
ALTER TABLE project MODIFY (id GENERATED BY DEFAULT ON NULL AS IDENTITY START WITH LIMIT VALUE);
ALTER TABLE issue MODIFY (id GENERATED BY DEFAULT ON NULL AS IDENTITY START WITH LIMIT VALUE);
